mapper.select:
select 
	general_seq as "general_seq", doc_seq as "doc_seq", purpose as "purpose", content as "content" 
from general where doc_seq = #{doc_seq}

select
	users_id as "users_id", step_order as "step_order"
from approval_lines where doc_seq = #{doc_seq} and users_id = #{users_id}

mapper.update:
update vacation 
set vac_type = #{vac_type}, start_date = #{start_date, jdbcType=DATE}, end_date = #{end_date, jdbcType=DATE}, 
	days = #{days}, reason = #{reason}
where doc_seq = #{doc_seq}

update payment 
set pay_date = #{pay_date, jdbcType=DATE}, total_amount = #{total_amount, jdbcType=NUMERIC}, 
	pay_reason = #{pay_reason, jdbcType=VARCHAR}, account_info = #{account_info, jdbcType=VARCHAR}
where pay_seq = #{pay_seq}

update purchase 
set total_amount = #{total_amount, jdbcType=NUMERIC}, purpose = #{purpose, jdbcType=VARCHAR}, 
vendor = #{vendor, jdbcType=VARCHAR}, purchase_date = #{purchase_date, jdbcType=DATE}
where purchase_seq = #{purchase_seq}

