		select * from (select row_number() over(order by d.created_at desc) rn, 
			d.*, u.name as name
			from draft_documents d
			inner join users u on d.users_id = u.id
			inner join approval_cc c on d.doc_seq = c.doc_seq
			where c.users_id = #{loginId} and d.status = #{status}


            	and lower(d.title) like '%' || lower(#{keyword}) || '%'



	            and d.doc_type = #{docType}


			)
			where rn between #{start} and #{end}

