select count(*) from draft_documents d
	where d.users_id = #{loginId} and status = #{status}


        and lower(d.title) like '%' || lower(#{keyword}) || '%'



        and d.doc_type = #{docType}

		select * from (select row_number() over(order by a.handle_at desc) rn, 
			d.*, u.name as name, u.sysname as sysname, a.status as app_status
			from approval_lines a
			inner join draft_documents d on a.doc_seq = d.doc_seq
			inner join users u on d.users_id = u.id
			where a.users_id = #{loginId} and a.status in ('APPROVED', 'REJECTED')


            	and lower(d.title) like '%' || lower(#{keyword}) || '%'



	            and d.doc_type = #{docType}


			)
			where rn between #{start} and #{end}

select count(*) from approval_lines a inner join draft_documents d on a.doc_seq = d.doc_seq where a.users_id = #{loginId} and a.status in ('APPROVED', 'REJECTED')
and lower(d.title) like '%' || lower(#{keyword}) || '%'
